final:
module SR_FlipFlop (  
    input wire S,  
    input wire R,  
    input wire clk,  
    output reg obf_Q  
);  
    always @(posedge clk) begin  
        if (S && !R)  
            obf_Q <= 1;  
        else if (!S && R)  
            obf_Q <= 0;  
        // if both S and R are 0, obf_Q retains its value  
    end  
endmodule
